CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE players (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),telegram_user_id bigint UNIQUE,display_name text NOT NULL,locale text NOT NULL DEFAULT 'en',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE creatures (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),player_id uuid REFERENCES players(id) ON DELETE CASCADE,slug text UNIQUE NOT NULL,name text NOT NULL,kind text NOT NULL CHECK (kind IN ('player','npc','system')),personality jsonb NOT NULL,genome jsonb NOT NULL,level integer NOT NULL DEFAULT 1,xp integer NOT NULL DEFAULT 0,energy integer NOT NULL DEFAULT 100 CHECK (energy BETWEEN 0 AND 100),mood text NOT NULL DEFAULT 'curious',current_location text NOT NULL DEFAULT 'cardboard_nest',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX creatures_player_idx ON creatures(player_id); CREATE INDEX creatures_kind_idx ON creatures(kind);
CREATE TABLE relationships (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),source_creature_id uuid NOT NULL REFERENCES creatures(id) ON DELETE CASCADE,target_creature_id uuid NOT NULL REFERENCES creatures(id) ON DELETE CASCADE,trust integer NOT NULL DEFAULT 0,affection integer NOT NULL DEFAULT 0,rivalry integer NOT NULL DEFAULT 0,last_event text,updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(source_creature_id,target_creature_id));
CREATE TABLE quests (id text PRIMARY KEY,title text NOT NULL,description text NOT NULL,trigger_type text NOT NULL,reward jsonb NOT NULL DEFAULT '{}',active boolean NOT NULL DEFAULT true);
CREATE TABLE quest_instances (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),quest_id text NOT NULL REFERENCES quests(id),creature_id uuid NOT NULL REFERENCES creatures(id) ON DELETE CASCADE,status text NOT NULL DEFAULT 'active',progress jsonb NOT NULL DEFAULT '{}',due_at timestamptz,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE memories (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),creature_id uuid NOT NULL REFERENCES creatures(id) ON DELETE CASCADE,source_type text NOT NULL,summary text NOT NULL,importance real NOT NULL DEFAULT 0.25,is_private boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE game_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),aggregate_id uuid NOT NULL,event_type text NOT NULL,payload jsonb NOT NULL,created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX game_events_aggregate_idx ON game_events(aggregate_id,created_at DESC);
CREATE TABLE world_events (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),creature_id uuid NOT NULL REFERENCES creatures(id) ON DELETE CASCADE,event_type text NOT NULL,payload jsonb NOT NULL DEFAULT '{}',status text NOT NULL DEFAULT 'pending',due_at timestamptz NOT NULL,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX world_events_due_idx ON world_events(status,due_at);
CREATE TABLE story_entries (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),creature_id uuid NOT NULL REFERENCES creatures(id) ON DELETE CASCADE,event_id uuid,title text NOT NULL,body text NOT NULL,choices jsonb NOT NULL DEFAULT '[]',reward jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX story_entries_creature_idx ON story_entries(creature_id,created_at DESC);
CREATE TABLE managed_bots (bot_id bigint PRIMARY KEY,owner_telegram_user_id bigint NOT NULL,creature_id uuid NOT NULL REFERENCES creatures(id) ON DELETE CASCADE,username text,token_cipher text NOT NULL,webhook_secret text NOT NULL,enabled boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE ai_profiles (player_id uuid PRIMARY KEY REFERENCES players(id) ON DELETE CASCADE,base_url text NOT NULL,model text NOT NULL,encrypted_api_key text NOT NULL,enabled boolean NOT NULL DEFAULT true,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE outbox (id uuid PRIMARY KEY DEFAULT gen_random_uuid(),bot_id bigint,chat_id text NOT NULL,payload jsonb NOT NULL,status text NOT NULL DEFAULT 'pending',attempts integer NOT NULL DEFAULT 0,available_at timestamptz NOT NULL DEFAULT now(),created_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX outbox_pending_idx ON outbox(status,available_at);
